// Initialize tracking variables
// This run will check for field changes against previous snapshot
return [{
  json: {
    timestamp: new Date().toISOString(),
    flow_name: 'Flow E - Re-Engagement',
    trigger_time: '07:00 ET',
    tracked_fields: ['physical_address', 'website', 'officer_name', 'num_sites'],
    changes_detected: 0,
    prospects_processed: 0,
    prospects_reengaged: 0
  }
}];

// Parse Airtable prospects and compare with snapshot
// Detect changes in tracked fields
const response = $node['Fetch All Prospects'].json || { records: [] };
const trackedFields = ['physical_address', 'website', 'officer_name', 'num_sites'];

const recordsWithChanges = response.records
  .filter(rec => rec.fields)
  .map(rec => {
    const current = rec.fields;
    const snapshot = current.last_field_snapshot ? JSON.parse(current.last_field_snapshot) : {};

    // Detect changes
    const changes = {};
    let hasChanges = false;

    trackedFields.forEach(field => {
      const currentValue = current[field] || '';
      const snapshotValue = snapshot[field] || '';

      if (currentValue !== snapshotValue && currentValue !== '') {
        changes[field] = {
          old_value: snapshotValue,
          new_value: currentValue
        };
        hasChanges = true;
      }
    });

    return {
      json: {
        record_id: rec.id,
        legal_name: current.legal_name || '',
        email: current.email || '',
        current_fields: {
          physical_address: current.physical_address || '',
          website: current.website || '',
          officer_name: current.officer_name || '',
          num_sites: current.num_sites || 0
        },
        snapshot_fields: snapshot,
        detected_changes: changes,
        has_changes: hasChanges,
        pipeline_status: current.pipeline_status || '',
        current_icebreaker: current.icebreaker || '',
        re_engagement_candidate: current.re_engagement_candidate || false
      }
    };
  })
  .filter(rec => rec.json.has_changes); // Only records with changes

return recordsWithChanges.length > 0 
  ? recordsWithChanges 
  : [{
      json: {
        message: 'No field changes detected',
        total_prospects_checked: response.records.length
      }
    }];

// Extract Claude response and prepare fresh icebreaker
// Claude returns: { icebreaker, intent_signal, segment, etc. }
const claudeResponse = $node['Call Claude for Fresh Icebreaker'].json || {};

return [{
  json: {
    record_id: $node['Filter - Has Field Changes'].json.record_id,
    legal_name: $node['Filter - Has Field Changes'].json.legal_name,
    email: $node['Filter - Has Field Changes'].json.email,
    detected_changes: $node['Filter - Has Field Changes'].json.detected_changes,
    new_icebreaker: claudeResponse.icebreaker || `I noticed some updates to your profile - let's reconnect!`,
    intent_signal: claudeResponse.intent_signal || 'medium',
    segment: claudeResponse.segment || 'Unknown',
    reason_for_reengagement: Object.keys($node['Filter - Has Field Changes'].json.detected_changes).join(', ')
  }
}];

// Fallback path: No changes detected
return [{
  json: {
    message: 'No field changes detected',
    total_prospects_checked: $node['Parse Prospects & Detect Changes'].json.total_prospects_checked || 0,
    timestamp: new Date().toISOString(),
    status: 'completed_no_changes'
  }
}];

// Aggregate results
const success = $node['Update Prospect - Set Re-Engagement'].json;
const audit = $node['Create Audit Log - Re-Engagement'].json;

return [{
  json: {
    status: 'completed',
    message: 'Flow E completed successfully',
    legal_name: success.legal_name,
    email: success.email,
    field_changes: success.detected_changes,
    new_icebreaker_generated: success.new_icebreaker !== undefined,
    pipeline_status_updated: 'pending_review',
    re_engagement_candidate_set: true,
    audit_logged: true,
    timestamp: new Date().toISOString()
  }
}];
